70	}: {
71	  toastId: ToastId;
72	  dismissAfterVisibleMs: number | undefined;
73	}) {
74	  useEffect(() => {
75	    if (!dismissAfterVisibleMs || dismissAfterVisibleMs <= 0) return;
76	    if (typeof window === "undefined" || typeof document === "undefined") return;
77	
78	    let remainingMs = threadToastVisibleTimeoutRemainingMs.get(toastId) ?? dismissAfterVisibleMs;
79	    let startedAtMs: number | null = null;
80	    let timeoutId: number | null = null;
81	    let closed = false;
82	
83	    const clearTimer = () => {
84	      if (timeoutId === null) return;
85	      window.clearTimeout(timeoutId);
86	      timeoutId = null;
87	    };
88	
89	    const closeToast = () => {
90	      if (closed) return;
91	      closed = true;
92	      threadToastVisibleTimeoutRemainingMs.delete(toastId);
93	      toastManager.close(toastId);
94	    };
95	
96	    const pause = () => {
97	      if (startedAtMs === null) return;
98	      remainingMs = Math.max(0, remainingMs - (Date.now() - startedAtMs));
99	      startedAtMs = null;
100	      clearTimer();
101	      threadToastVisibleTimeoutRemainingMs.set(toastId, remainingMs);
102	    };
103	
104	    const start = () => {
105	      if (closed || startedAtMs !== null) return;
106	      if (remainingMs <= 0) {
107	        closeToast();
108	        return;
109	      }
110	      startedAtMs = Date.now();
111	      clearTimer();
112	      timeoutId = window.setTimeout(() => {
113	        remainingMs = 0;
114	        startedAtMs = null;
115	        closeToast();
116	      }, remainingMs);
117	    };
118	
119	    const syncTimer = () => {
120	      const shouldRun = document.visibilityState === "visible" && document.hasFocus();
121	      if (shouldRun) {
122	        start();
123	        return;
124	      }
125	      pause();
