15	    const current = workerPool.getDiffRenderOptions();
16	    if (current.theme === themeName) {
17	      return;
18	    }
19	
20	    void workerPool
21	      .setRenderOptions({
22	        ...current,
23	        theme: themeName,
24	      })
25	      .catch(() => undefined);
26	  }, [themeName, workerPool]);
27	
28	  return null;
