### 5. Migration Strategy

In the rewritten `useTheme.ts`, the module-level initialization block includes a one-time migration:

```typescript
function migrateFromV1(): ThemePreference {
  const OLD_KEY = "t3code:theme";
  const NEW_KEY = "t3code:theme:v2";

  // If v2 key already exists, use it
  const v2 = localStorage.getItem(NEW_KEY);
  if (v2 !== null) return parsePreference(v2);

  // Migrate from v1
  const v1 = localStorage.getItem(OLD_KEY);
  let preference: ThemePreference = "system";
  if (v1 === "dark") preference = "t3-dark";
  else if (v1 === "light") preference = "t3-light";
  // "system" stays "system"

  localStorage.setItem(NEW_KEY, preference);
  localStorage.removeItem(OLD_KEY);
  return preference;
}
```

