153	const CODEX_MODEL_SLUGS = new Set<string>(getModelOptions("codex").map((option) => option.slug));
154	
155	function inferProviderForThreadModel(input: {
156	  readonly model: string;
157	  readonly sessionProviderName: string | null;
158	}): ProviderKind {
159	  if (input.sessionProviderName === "codex") {
160	    return input.sessionProviderName;
161	  }
162	  const normalizedCodex = normalizeModelSlug(input.model, "codex");
163	  if (normalizedCodex && CODEX_MODEL_SLUGS.has(normalizedCodex)) {
164	    return "codex";
165	  }
166	  return "codex";
167	}
