import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  T3_DARK_THEME,
  T3_LIGHT_THEME,
  type ThemeColors,
  type ThemeDefinition,
  type ThemePreference,
  getThemeById,
  isBuiltInThemeId,
} from "@t3tools/shared/theme";

export type { ThemePreference };

// ── Constants ───────────────────────────────────────────────────────

type ThemeSnapshot = {
  preference: ThemePreference;
  systemDark: boolean;
};

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

const DEFAULT_DARK_THEME = T3_DARK_THEME;
const DEFAULT_LIGHT_THEME = T3_LIGHT_THEME;

/** Keys of ThemeColors that are applied as CSS custom properties. */
const THEME_COLOR_KEYS: ReadonlyArray<keyof ThemeColors> = [
  "background",
  "foreground",
  "accent",
  "sidebar",
  "editor",
  "terminal",
  "statusBar",
];

// ── Internals ───────────────────────────────────────────────────────

/** Convert a ThemeColors key to its CSS custom-property name. */
function toCssPropertyName(key: keyof ThemeColors): string {
  // "statusBar" → "--theme-status-bar"; single-word keys stay as-is.
  return `--theme-${key.replace(/[A-Z]/g, (ch) => `-${ch.toLowerCase()}`)}`;
}

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/**
 * Read and normalize the stored preference.
 * Migrates legacy "light" / "dark" values to "t3-light" / "t3-dark".
 */
function getStored(): ThemePreference {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (raw === "system") return "system";
  if (typeof raw === "string" && isBuiltInThemeId(raw)) return raw;
  return "system";
}

function resolveThemeDefinition(preference: ThemePreference, systemDark: boolean): ThemeDefinition {
  if (preference === "system") {
    return systemDark ? DEFAULT_DARK_THEME : DEFAULT_LIGHT_THEME;
  }
  return getThemeById(preference) ?? DEFAULT_DARK_THEME;
}

function applyThemeProperties(theme: ThemeDefinition) {
  const root = document.documentElement;
  for (const key of THEME_COLOR_KEYS) {
    root.style.setProperty(toCssPropertyName(key), theme.colors[key]);
  }
}

function applyTheme(preference: ThemePreference, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const systemDark = getSystemDark();
  const theme = resolveThemeDefinition(preference, systemDark);
  document.documentElement.classList.toggle("dark", theme.appearance === "dark");
  applyThemeProperties(theme);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

// ── External-store plumbing ─────────────────────────────────────────

function getSnapshot(): ThemeSnapshot {
  const preference = getStored();
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.preference === preference &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ── Hook ────────────────────────────────────────────────────────────

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const preference = snapshot.preference;

  const activeTheme = resolveThemeDefinition(preference, snapshot.systemDark);
  const resolvedTheme: "light" | "dark" = activeTheme.appearance;

  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(preference);
  }, [preference]);

  return {
    /** The user's stored preference ("system" or a built-in theme ID). */
    theme: preference,
    /** Update the theme preference. */
    setTheme,
    /** "light" | "dark" — backward-compatible resolved appearance. */
    resolvedTheme,
    /** The fully-resolved ThemeDefinition with all semantic colors. */
    activeTheme,
  } as const;
}

