// ── Option model ────────────────────────────────────────────────────

interface ThemeOption {
  readonly value: ThemePreference;
  readonly label: string;
  readonly description: string;
  readonly previewTheme: ThemeDefinition | null;
}

const THEME_OPTIONS: readonly ThemeOption[] = [
  {
    value: "system",
    label: "System",
    description: "Automatically match your OS appearance.",
    previewTheme: null,
  },
  ...BUILT_IN_THEMES.map(
    (theme): ThemeOption => ({
      value: theme.id as ThemePreference,
      label: theme.name,
      description:
        theme.appearance === "dark"
          ? "Dark theme with curated colors."
          : "Light theme with curated colors.",
      previewTheme: theme,
    }),
  ),
];

// ── Preview swatches ────────────────────────────────────────────────

/**
 * Miniature preview of a single theme rendered as a tiny app layout:
 * sidebar | editor area + status bar, with an accent dot.
 */
function ThemePreviewSwatch({ theme }: { theme: ThemeDefinition }) {
  const { colors } = theme;
  return (
    <div
      className="relative flex h-9 w-16 shrink-0 overflow-hidden rounded-md border border-border"
      aria-hidden="true"
    >
