          <div className="mx-1 mt-0.5 h-0.5 w-3 rounded-full opacity-25" style={{ backgroundColor: colors.foreground }} />
        </div>
        <div className="flex h-2 items-center" style={{ backgroundColor: colors.statusBar }}>
          <div className="ml-1 size-1 rounded-full" style={{ backgroundColor: colors.accent }} />
        </div>
      </div>
    </div>
  );
}

/**
 * Split-preview showing the default light and dark themes side-by-side
 * to visually communicate "system / auto" behavior.
 */
function SystemPreviewSwatch() {
  const light = T3_LIGHT_THEME;
  const dark = T3_DARK_THEME;
  return (
    <div
      className="relative flex h-9 w-16 shrink-0 overflow-hidden rounded-md border border-border"
      aria-hidden="true"
    >
      {/* Left half — light */}
      <div className="flex w-1/2 flex-col overflow-hidden">
        <div className="flex flex-1">
          <div className="w-2" style={{ backgroundColor: light.colors.sidebar }} />
          <div className="flex-1" style={{ backgroundColor: light.colors.editor }} />
        </div>
        <div className="h-1.5" style={{ backgroundColor: light.colors.statusBar }} />
      </div>
      {/* Right half — dark */}
      <div className="flex w-1/2 flex-col overflow-hidden">
        <div className="flex flex-1">
          <div className="w-2" style={{ backgroundColor: dark.colors.sidebar }} />
          <div className="flex-1" style={{ backgroundColor: dark.colors.editor }} />
        </div>
        <div className="h-1.5" style={{ backgroundColor: dark.colors.statusBar }} />
      </div>
    </div>
  );
}

// ── Selector ────────────────────────────────────────────────────────

export function ThemeSelector() {
  const { theme, setTheme, activeTheme } = useTheme();

  return (
    <div>
      <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
        {THEME_OPTIONS.map((option) => {
          const selected = theme === option.value;
          return (
            <button
              key={option.value}
              type="button"
              role="radio"
              aria-checked={selected}
              className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors ${
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent"
              }`}
              onClick={() => setTheme(option.value)}
            >
              {option.previewTheme ? (
                <ThemePreviewSwatch theme={option.previewTheme} />
              ) : (
                <SystemPreviewSwatch />
              )}
              <span className="flex flex-1 flex-col">
                <span className="text-sm font-medium">{option.label}</span>
                <span className="text-xs">{option.description}</span>
              </span>
              {selected ? (
                <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{activeTheme.name}</span>
      </p>
    </div>
  );
}

