/**
 * Theme definitions for the T3 Code UI.
 *
 * Each built-in theme specifies a base appearance ("light" | "dark") and
 * colors for seven semantic UI areas.  The web app applies these as CSS
 * custom properties so every surface can react to the active theme.
 */

// ── Color contract ──────────────────────────────────────────────────

export interface ThemeColors {
  /** Primary page / app background */
  readonly background: string;
  /** Default text color */
  readonly foreground: string;
  /** Brand / interactive accent color */
  readonly accent: string;
  /** Sidebar navigation surface */
  readonly sidebar: string;
  /** Editor / main content surface */
  readonly editor: string;
  /** Integrated terminal surface */
  readonly terminal: string;
  /** Bottom status bar surface */
  readonly statusBar: string;
}

// ── Theme definition ────────────────────────────────────────────────

export interface ThemeDefinition {
  /** Unique slug identifier (e.g. "t3-dark") */
  readonly id: string;
  /** Human-readable display name */
  readonly name: string;
  /** Base appearance — drives the CSS `dark` class toggle */
  readonly appearance: "light" | "dark";
  /** Semantic color palette */
  readonly colors: ThemeColors;
}

// ── Built-in theme ID union ─────────────────────────────────────────

export type BuiltInThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * Value stored in local-storage: either "system" (auto-detect from OS)
 * or a specific built-in theme ID.
 */
export type ThemePreference = "system" | BuiltInThemeId;

// ── Individual theme constants ──────────────────────────────────────

export const T3_DARK_THEME: ThemeDefinition = {
  id: "t3-dark",
  name: "T3 Dark",
  appearance: "dark",
  colors: {
    background: "#0a0a0b",
    foreground: "#e5e5e5",
    accent: "#6366f1",
    sidebar: "#111113",
    editor: "#0a0a0b",
    terminal: "#080809",
    statusBar: "#111113",
  },
};

export const T3_LIGHT_THEME: ThemeDefinition = {
  id: "t3-light",
  name: "T3 Light",
  appearance: "light",
  colors: {
    background: "#ffffff",
    foreground: "#1c1c1e",
    accent: "#4f46e5",
    sidebar: "#f5f5f7",
    editor: "#ffffff",
    terminal: "#f0f0f2",
    statusBar: "#f5f5f7",
  },
};

export const T3_MIDNIGHT_THEME: ThemeDefinition = {
  id: "t3-midnight",
  name: "T3 Midnight",
  appearance: "dark",
  colors: {
    background: "#020617",
    foreground: "#e2e8f0",
    accent: "#818cf8",
    sidebar: "#0f172a",
    editor: "#020617",
    terminal: "#010410",
    statusBar: "#0f172a",
  },
};

// ── Aggregated list ─────────────────────────────────────────────────

export const BUILT_IN_THEMES: readonly ThemeDefinition[] = [
  T3_DARK_THEME,
  T3_LIGHT_THEME,
  T3_MIDNIGHT_THEME,
];

// ── Helpers ─────────────────────────────────────────────────────────

const BUILT_IN_THEME_MAP = new Map<string, ThemeDefinition>(
  BUILT_IN_THEMES.map((t) => [t.id, t]),
);

export function getThemeById(id: string): ThemeDefinition | undefined {
  return BUILT_IN_THEME_MAP.get(id);
}

export function isBuiltInThemeId(id: string): id is BuiltInThemeId {
  return BUILT_IN_THEME_MAP.has(id);
}

